#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
    int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e7+10;
int pm[N>>3],cpt,mu[N<<1];bool vs[N];
inline void Init(int mx=N-10)
{
    mu[1]=1;vs[1]=1;rep(2,mx,i)
    {
        vs[i]?0:(mu[pm[++cpt]=i]=-1);
        for(int j=1;j<=cpt&&pm[j]*i<=mx;++j)
        {
            vs[pm[j]*i]=1;if(i%pm[j]==0)break;
            mu[pm[j]*i]=-mu[i];
        }
    }
    rep(1,mx,i)mu[i]=bool(mu[i])+mu[i-1];return;
}
int sn,smu[1010],k;
inline int Solve(int n,int d=1)
{
    if(n<=N-10)return mu[n];if(smu[d])return smu[d];
    int res=n;for(int i=2;i*i<=n;++i)res-=Solve(n/(i*i),d*i*i);
    return smu[d]=res;
}
inline bool check(int Q)
{
    sn=Q;memset(smu,0,sizeof(smu));
    return Solve(Q)>=k;
}
inline void Main()
{
    k=read();int l=1,r=k<<1,mid,res;
    while(l<=r)check(mid=(1ll*l+r)>>1)?(r=mid-1,res=mid):(l=mid+1);
    printf("%d\n",res);return;
}
int main(){Init();int T=read();while(T--)Main();return 0;}
